import { parseRobotsTxt, validateRobots } from '@nuxtjs/robots/util'
import { defineEventHandler, getQuery } from 'h3'
import { getSiteConfig } from '#site-config/server/composables/getSiteConfig'
import { getSiteRobotConfig } from '../../composables/getSiteRobotConfig'
import { useRuntimeConfigNuxtRobots } from '../../composables/useRuntimeConfigNuxtRobots'

export default defineEventHandler(async (e) => {
  const runtimeConfig = useRuntimeConfigNuxtRobots(e)
  const { indexable, hints } = getSiteRobotConfig(e)
  const siteConfig = getSiteConfig(e)
  // @ts-expect-error Nuxt typed routes cause excessive type depth with $fetch
  const robotsTxt: string = await e.$fetch('/robots.txt', {
    query: getQuery(e),
  })
  const parsed = validateRobots(parseRobotsTxt(robotsTxt))
  return {
    robotsTxt,
    indexable,
    hints,
    runtimeConfig,
    siteConfig: {
      url: siteConfig.url,
      env: siteConfig.env,
      indexable: siteConfig.indexable,
    },
    validation: {
      errors: parsed.errors,
      warnings: parsed.warnings,
      groups: parsed.groups.length,
      sitemaps: parsed.sitemaps,
    },
  }
})

import type { ResolvedCollection } from './collection'
import type { ContentFile, ParsedContentFile } from './content'
import type { PathMetaOptions } from './path-meta'

// Parser options interface
interface ParserOptions {
  pathMeta: PathMetaOptions
  markdown: {
    compress: boolean
    rehypePlugins: Record<string, unknown>
    remarkPlugins: Record<string, unknown>
    [key: string]: unknown
  }
}

// Hook context for beforeParse
export interface FileBeforeParseHook {
  file: ContentFile
  collection: ResolvedCollection
  parserOptions: ParserOptions
}

// Hook context for afterParse
export interface FileAfterParseHook {
  file: ContentFile
  content: ParsedContentFile
  collection: ResolvedCollection
}

// Declare module to extend Nuxt hooks
declare module '@nuxt/schema' {
  interface NuxtHooks {
    'content:file:beforeParse': (ctx: FileBeforeParseHook) => Promise<void> | void
    'content:file:afterParse': (ctx: FileAfterParseHook) => Promise<void> | void
  }
}

import type { Nuxt } from '@nuxt/schema'
import type { ModuleOptions } from '../module'

export type ProviderSetup = (providerOptions: ImageModuleProvider, moduleOptions: ModuleOptions, nuxt: Nuxt)
=> void | Promise<void>

export interface InputProvider<T = any> {
  name?: string
  provider?: string
  options?: T
  setup?: ProviderSetup
}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ProviderDefaults {}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ConfiguredImageProviders {}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ImageProviders {}

export interface ImageModuleProvider {
  name: string
  importName: string
  options: any
  provider: string
  runtime: string
  runtimeOptions: any
  setup: ProviderSetup
}

import type { State } from 'mdast-util-to-hast'
import type { Element, Properties } from 'hast'
import type { Nodes as MdastContent } from 'mdast'

type Node = MdastContent & {
  name: string
  attributes?: Properties
  fmAttributes?: Properties
}

export default function containerComponent(state: State, node: Node) {
  const result: Element = {
    type: 'element',
    tagName: node.name,
    properties: {
      ...node.attributes,
      ...node.data?.hProperties,
    },
    children: state.all(node),
  }
  state.patch(node, result)

  // @ts-expect-error Inline attributes that passed in MDC sysntax `:component{...attributes}`
  result.attributes = node.attributes

  // @ts-expect-error Attributes define using FrontMatter syntax and YAML format
  result.fmAttributes = node.fmAttributes

  return result
}
